(() => {
  const extractPageData = () => {
    const items = [];
    const elements = document.querySelectorAll('.Card.SearchResult-Card');

    elements.forEach(el => {
      const titleEl = el.querySelector('.ContentItem-title a');
      const title = titleEl?.textContent?.trim() || '';
      const url = titleEl?.href || '';

      const imageEl = el.querySelector('.RichContent-cover img');
      const image = imageEl?.src || '';

      const voteButton = el.querySelector('.VoteButton--up');
      const voteText = voteButton?.textContent?.trim() || '';
      const upvotes = voteText.includes('赞同') ? voteText.replace('赞同', '').trim() || '0' : '0';

      const commentButton = el.querySelector('.ContentItem-action:has(.ZDI--ChatBubbleFill24)');
      const commentText = commentButton?.textContent?.trim() || '';
      const comments = commentText.includes('添加评论') ? '0' : commentText;

      const timeEl = el.querySelector('.SearchItem-time');
      const time = timeEl?.textContent?.trim() || '';

      const item = {
        title,
        url,
        image,
        upvotes,
        comments,
        time
      };

      if (item.title && item.url) {
        items.push(item);
      }
    });

    return items;
  };

  const paginationClick = async (pageNumber) => {
    const prevData = extractPageData();
    const nextButton = document.querySelector('.Pagination .PaginationButton--next, .Pagination .next, .Pagination-button--next');
    if (!nextButton) return [];

    nextButton.click();

    for (let i = 0; i < 50; i++) {
      await new Promise(resolve => setTimeout(resolve, 300));
      const newData = extractPageData();
      if (newData.length > 0 && prevData.length > 0 && 
          newData[0].title !== prevData[0].title) {
        return newData;
      }
    }
    return [];
  };

  const getAllPagesData = async () => {
    let allData = [...extractPageData()];
    const paginationEl = document.querySelector('.Pagination');

    if (paginationEl) {
      const pageButtons = document.querySelectorAll('.Pagination .PaginationButton, .Pagination .page, .Pagination-item');
      const totalPages = pageButtons.length;

      for (let i = 2; i <= totalPages; i++) {
        const pageData = await paginationClick(i);
        if (pageData.length === 0) break;
        allData = [...allData, ...pageData];
      }
    }

    return allData;
  };

  return getAllPagesData();
})()
